head.script:
/**
 * @component
 * @componentName udc_win
 * @pluginName
 * @company
 * @developer
 * @category /cm/gcc
 * @notSupportBrowser
 * @version
 * @htmlRender
 * @icon
 * @disableIcon
 * @description
 * @width
 * @height
 * @license
 * @imagePath
 * @homepage
 */
// =============================================================================
/**
 * 업무 화면 영역 제어(권한, 업무 화면 공통 UI 요소 및 버튼 제어, 개인화 등) 함수를 작성한다.
 *
 * @author Inswave Systems
 * @class win
 * @namespace $c.win
 */
// =============================================================================

// 메시지 레이어 인덱스
scwin.MESSAGE_IDX = 1;

// 메세지 알림 콜백 Function 정보 저장
scwin.CB_FUNCTION_MANAGER = {
    cbFuncIdx: 0, // 정보 저장 Index Key
    cbFuncSave: {} // 정보 저장 객체
};

scwin.onpageload = function () {
    requires("uiplugin.popup");
};

scwin.isAuthFreePage = function (src) {
    let normalizedSrc = (src || "").toString().toLowerCase();

    if (!normalizedSrc) {
        return false;
    }

    try {
        const contextPath = ($c.sbm.getContextPath() || "").toLowerCase();
        if (contextPath && normalizedSrc.indexOf(contextPath) === 0) {
            normalizedSrc = normalizedSrc.substring(contextPath.length);
        }
    } catch (e) {}

    try {
        if (normalizedSrc.indexOf("w2xpath=") > -1) {
            let querySrc = normalizedSrc.substring(normalizedSrc.indexOf("w2xpath=") + 8);
            if (querySrc.indexOf("&") > -1) {
                querySrc = querySrc.substring(0, querySrc.indexOf("&"));
            }
            querySrc = decodeURIComponent(querySrc || "");
            if (querySrc) {
                normalizedSrc = querySrc.toLowerCase();
            }
        }
    } catch (e) {}

    if (normalizedSrc.indexOf("?") > -1) {
        normalizedSrc = normalizedSrc.substring(0, normalizedSrc.indexOf("?"));
    }

    return normalizedSrc.indexOf("commonpopup.xml") > -1
        || normalizedSrc.indexOf("commonpopup2.xml") > -1
        || normalizedSrc.indexOf("commonpopupncall.xml") > -1
        || normalizedSrc.indexOf("ilcommonpopup.xml") > -1
        || normalizedSrc.indexOf("groupcodepopup.xml") > -1
        || normalizedSrc.indexOf("commonfilepopup.xml") > -1
        || normalizedSrc.indexOf("commonsinglefilepopup.xml") > -1
        || normalizedSrc.indexOf("commonscreenhostpopup.xml") > -1
        || normalizedSrc.indexOf("zz_690_01_06b_2.xml") > -1
        || normalizedSrc.indexOf("zz_690_01_06p_2.xml") > -1
        || normalizedSrc.indexOf("op_900_10_01p.xml") > -1
        || normalizedSrc.indexOf("ilcommoncustomerchange.xml") > -1
        || normalizedSrc.indexOf("ilcommonhawbnochange.xml") > -1
        || normalizedSrc.indexOf("ilcommondeptchange.xml") > -1
        || normalizedSrc.indexOf("ilcommonedircvselection.xml") > -1
        || normalizedSrc.indexOf("ilcommonfilepopup.xml") > -1
        || normalizedSrc.indexOf("ilcommonfilepopup_02.xml") > -1
        || normalizedSrc.indexOf("ilcommonviewattachedfilepopup.xml") > -1
        || normalizedSrc.indexOf("ilcommonresultdatechange.xml") > -1
        || normalizedSrc.indexOf("ilcommonviewattachedfilepopup1.xml") > -1
        || normalizedSrc.indexOf("ozreportpopup.xml") > -1
        || normalizedSrc.indexOf("ozreportcomp.xml") > -1
        || normalizedSrc.indexOf("zipcodepopup.xml") > -1
        || normalizedSrc.indexOf("zipcodepopupncall.xml") > -1
        || normalizedSrc.indexOf("newzipcodepopup.xml") > -1
        || normalizedSrc.indexOf("autopopup") > -1
        || normalizedSrc.indexOf("filemultiupload.xml") > -1
        || normalizedSrc.indexOf("filemultiuploadpreview.xml") > -1
        || normalizedSrc.indexOf("advancedfileupload") > -1
        || normalizedSrc.indexOf("advancedmultiupload") > -1
        || normalizedSrc.indexOf("csvfileupload") > -1
        || normalizedSrc.indexOf("/_websquare_/uiplugin/grid/upload/") > -1
        || normalizedSrc.indexOf("fileupload.jsp") > -1
        || normalizedSrc.indexOf("zoom.xml") > -1
        || normalizedSrc.indexOf("/sample/") > -1
        || normalizedSrc.indexOf("zz_620_01_00b.xml") > -1
        || normalizedSrc.indexOf("zz_620_01_02b.xml") > -1
        || normalizedSrc.indexOf("zz_620_01_03b.xml") > -1
        || normalizedSrc.indexOf("zz_620_01_04b.xml") > -1
        || normalizedSrc.indexOf("zz_620_01_04b_01.xml") > -1
        || normalizedSrc.indexOf("zz_620_01_04b_02.xml") > -1
        || normalizedSrc.indexOf("zz_620_01_06b.xml") > -1
        || normalizedSrc.indexOf("op_202_02_23p.xml") > -1
        || normalizedSrc.indexOf("auth.xml") > -1;

};

scwin.PROGRAM_LOG_SUBMISSION_SEQ = 0;

scwin.normalizeProgramLogId = function (pgmId) {
    return (pgmId || "").toString().split("?")[0].split("#")[0].replace(/\.xml$/i, ".jsp");
};

scwin.shouldWriteProgramUseLog = function (url, pgmId) {
    const normalizedPgmId = scwin.normalizeProgramLogId(pgmId).toLowerCase();
    const normalizedUrl = (url || "").toString().toLowerCase();

    if (!normalizedPgmId) {
        return false;
    }

    if (normalizedPgmId === "auth_failed.jsp") {
        return false;
    }

    if (normalizedUrl.indexOf("xml/messagebox.xml") > -1) {
        return false;
    }

    return !scwin.isAuthFreePage(url);
};

scwin.writeProgramUseLog = function (url, pgmId) {
    const normalizedPgmId = scwin.normalizeProgramLogId(pgmId);

    if (!scwin.shouldWriteProgramUseLog(url, normalizedPgmId)) {
        return Promise.resolve(false);
    }

    const submissionId = "sbm_programUseLog_" + (++scwin.PROGRAM_LOG_SUBMISSION_SEQ);

    return $c.sbm.executeDynamic({
        id: submissionId,
        action: "/programLogToDBMS.do",
        method: "post",
        mediatype: "application/json",
        mode: "asynchronous",
        isProcessMsg: false
    }, {
        PGM_ID: normalizedPgmId
    }).then(function () {
        return true;
    }).catch(function (e) {
        console.error("program use log submit failed", e);
        return false;
    }).then(function (result) {
        try {
            $p.deleteSubmission(submissionId);
        } catch (e) {}

        return result;
    });
};

/**
 * @method 
 * @name __getI18NUrl
 * @description 다국어 처리함수
 * @param {String} xmlUrl 전체 URL중 w2xPath이하의 경로
 * @hidden N
 * @exception 
 * @example
 * $c.getI18NUrl( "/ui/SW/request.xml" ); 
 * //return 예시)"/websquare/I18N?w2xPath=/ui/SW/request.xml"
 */
scwin.__getI18NUrl = function (xmlUrl) {
    const contextPath = $c.sbm.getContextPath();
    const baseURL = contextPath + "/I18N";
    let rsURL = "";
    const locale = WebSquare.cookie.getCookie("locale");
    const bXml = "/blank.xml";

    xmlUrl = $c.util.getParameter("w2xPath", xmlUrl) || xmlUrl;
    xmlUrl = xmlUrl.replace(/\?.*/, "");

    if (xmlUrl.search(bXml) > -1 && xmlUrl.search(WebSquare.baseURI) == -1) {
        xmlUrl = WebSquare.baseURI + "/blank.xml";
    }

    rsURL = baseURL + "?w2xPath=" + WebSquare.jsLoader.getUri(WebSquare.core.getURL(xmlUrl));

    if (locale != null && locale != '') {
        rsURL = rsURL + "&locale=" + unescape(locale);
    }

    return rsURL;
};

/**
 * @method
 * @name getScope
 * @description 컴포넌트의 현재 scope 정보를 반환한다.
 * @param {string} comObj 컴포넌트 객체
 * @hidden N
 * @exception 
 * @example ${example}
 */
scwin.getScope = function (comObj) {
    if (typeof (comObj) == 'undefined') {
        const scopeApi = $p;
        return $c.win.__getScope(scopeApi);
    }

    return $c.win.__getScope(comObj);
};

/**
 * @method
 * @name __getScope
 * @description $p를 파라미터로 직접 전달하는 getScope
 * @param {Object} comObj 컴포넌트 객체
 * @returns
 * @hidden N
 * @exception
 * @example
 */
scwin.__getScope = function (comObj) {
    try {
        if (typeof comObj === "string") {
            const scopeObj = $c.util.getComponent(comObj);
            if (scopeObj !== null) {
                return scopeObj.getScopeWindow();
            }
        } else {
            return comObj.getScopeWindow();
        }
    } catch (ex) {
        console.error(ex);
        return null;
    }
};

/**
 * @method 
 * @name getActiveWindowInfo
 * @description 현재 활성화된 실행 프레임 윈도우 정보를 반환한다.
 * @param {Object} scopeApi 객체 컴포넌트 객체 또는 아이디(pageFrame Scope 경로를 포함한 Full Path Id)
 * @returns {Object} activeInfo 현재 Active Window 정보 반환
 * {String} activeinfo.type : 액티브 윈도우 타입 [P : 팝업, T: 탭컨텐츠, W: 윈도우컴포넌트]
 * {Object} activeinfo.window : 액티브 윈도우 객체
 * {String} activeinfo.programCd : 액티브 윈도우 프로그램 코드
 * @hidden N
 * @exception 
 * @example
 */
scwin.getActiveWindowInfo = function (scopeApi) {

    // $p를 직접 넣은 경우.
    if (typeof (scopeApi) == 'object') {
        $p = scopeApi;
    };

    const activeInfo = {
        "type": "", // T:Tabcontrol, W:windowContainer, P:popup
        "window": "", // Window객체
        "programCd": "" // 프로그램 코드 (팝업인경우는 예외)
    };

    const popupList = $p.getPopupWindowList();
    let popupWindow = null;

    if (popupList.length > 0) {
        for (let i = popupList.length - 1; i > -1; i--) {
            if (document.activeElement.id != '' && document.activeElement.id + "_pageFrame" === popupList[i].$p.getFrameId()) {
                popupWindow = $p.getPopupWindow(document.activeElement.id);
            }
        }
    }

    let findProgramList;
    if (popupWindow !== null) {
        // pageFrame Popup 방식으로 오픈된 팝업 화면
        activeInfo["type"] = "P";
        activeInfo["pgmId"] = $c.win.getProgramId(popupWindow.$p);
        activeInfo["window"] = popupWindow;
    } else if (typeof typeof $p.top().tac_layout !== "undefined") {
        // TabControl 또는 WindowContainer를 통해서 오픈된 업무 화면
        // activeInfo["type"] = $p.main().main.getLayoutId();
        activeInfo["type"] = "T";
        if (activeInfo["type"] == "T") {
            const selectedTabId = $p.top().tac_layout.getSelectedTabID();
            findProgramList = $c.win.getMainFrame().ds_allMenuList.getMatchedJSON("actPgmId", selectedTabId, false);
            if (findProgramList.length > 0) {
                activeInfo["pgmId"] = findProgramList[0].actPgmId;
            } else {
                let fullPgmId= "";
                if(selectedTabId.indexOf(".jsp") == -1) {
                    fullPgmId = selectedTabId+".jsp";
                }
                activeInfo["pgmId"] = fullPgmId;
            }
            activeInfo["window"] = $c.win.getMainFrame().tac_layout.getWindow(selectedTabId);
        } else if (activeInfo["type"] == "M") {
            const selectedWindowId = $p.main().wdc_main.getSelectedWindowId();
            findProgramList = $c.data.menuComp.getMatchedJSON("actPgmId", selectedWindowId, true);
            if (findProgramList.length > 0) {
                activeInfo["pgmId"] = findProgramList[0].actPgmId;
            }
            activeInfo["window"] = $p.main().wdc_main.getWindow(selectedWindowId);
        } else if (activeInfo["type"] == "S") {
            if (!$c.util.isEmpty($c.data.getParameter($p.main().pfm_layout.getWindow().$p, "menuInfo"))) {
                activeInfo["pgmId"] = $c.data.getParameter($p.main().pfm_layout.getWindow().$p, "menuInfo").programCd;
            }
            activeInfo["window"] = $p.main().pfm_layout.getWindow();
        }
    } else {
        // Window Popup 방식으로 오픈된 팝업 화면
        activeInfo["type"] = "P";
        activeInfo["pgmId"] = $c.win.getProgramId();
        activeInfo["window"] = $p.getFrame();
    }

    return activeInfo;
};

/**
 * @method 
 * @name showToastMessage
 * @description 토스트 메시지를 보여준다.
 * @param {String} messageType 메시지 종류 ( 에러 : scwin.MESSAGE_CODE.STATUS_ERROR, 성공 : scwin.MESSAGE_CODE.STATUS_SUCCESS, 경고 : scwin.MESSAGE_CODE.STATUS_WARNING, 정보 : scwin.MESSAGE_CODE.STATUS_INFO )
 * @param {String} message 메시지
 * @hidden N
 * @exception 
 * @example
$c.win.showToastMessage($c.sbm.getMessageCode('STATUS_SUCCESS'), e.responseJSON.rsMsg.statusMsg);
 */
scwin.showToastMessage = function (messageType, message) {

    if ($c.util.isEmpty($p.main().pfm_footer)) {
        return;
    }

    const messageIdx = new Date().getTime();

    const pgfFooter = $p.main().pfm_footer.getWindow();
    let className = "";

    if ($c.sbm.getMessageCode('STATUS_ERROR') === messageType) {
        className = "error";
    } else if ($c.sbm.getMessageCode('STATUS_SUCCESS') === messageType) {
        className = "success";
    } else if ($c.sbm.getMessageCode('STATUS_WARNING') === messageType) {
        className = "warning";
    } else {
        className = "info";
    }

    pgfFooter.$p.dynamicCreate("grp_notice_" + messageIdx, "group", { style: "opacity: 0.0;" }, pgfFooter.grp_noticeArea);
    let grpNotice = pgfFooter.$p.getComponentById("grp_notice_" + messageIdx);
    grpNotice.addClass("notice");

    pgfFooter.$p.dynamicCreate("grp_noticeInfo_" + messageIdx, "group", { style: "opacity: 0.0" }, grpNotice);
    let grpNoticeInfo = pgfFooter.$p.getComponentById("grp_noticeInfo_" + messageIdx);
    grpNoticeInfo.addClass(className);

    pgfFooter.$p.dynamicCreate("tbx_message_" + messageIdx, "textbox", { style: "display:inline; margin-left:3px", label: message }, grpNoticeInfo);

    pgfFooter.$p.$("#" + grpNotice.getID()).fadeTo(1000, 1);
    pgfFooter.$p.$("#" + grpNoticeInfo.getID()).fadeTo(1000, 1);

    $c.util.setTimeout(
        function (idx) {
            let grpNotice = pgfFooter.$p.getComponentById("grp_notice_" + idx);
            if (!$c.util.isEmpty(grpNotice)) {
                pgfFooter.$p.$("#" + grpNotice.getID()).fadeTo(1000, 0);
            }

            let grpNoticeInfo = pgfFooter.$p.getComponentById("grp_noticeInfo_" + idx);
            if (!$c.util.isEmpty(grpNoticeInfo)) {
                pgfFooter.$p.$("#" + grpNoticeInfo.getID()).fadeTo(1000, 0);
            }

            $c.util.setTimeout(
                function (idx) {
                    const tbxMessage = pgfFooter.$p.getComponentById("tbx_message_" + idx);
                    if (!$c.util.isEmpty(tbxMessage)) {
                        tbxMessage.remove();
                    }

                    let grpNoticeInfo = pgfFooter.$p.getComponentById("grp_noticeInfo_" + idx);
                    if (!$c.util.isEmpty(grpNoticeInfo)) {
                        grpNoticeInfo.remove();
                    }

                    let grpNotice = pgfFooter.$p.getComponentById("grp_notice_" + idx);
                    if (!$c.util.isEmpty(grpNotice)) {
                        grpNotice.remove();
                    }

                    let objArr = $c.util.getChildren(pgfFooter.grp_noticeArea, {
                        includePlugin: "group textbox",
                        recursive: true
                    });
                },
                { delay: 1500, args: [idx], key: "MessageRemove" + idx }
            );

        },
        { delay: 3000, args: [messageIdx], key: "MessageFadeOut" + messageIdx }
    );
};


/**
 * @method 
 * @name openMenu
 * @description 특정 메뉴를 오픈한다.
 * @param {String} menuNm 메뉴명 - 단위화면에서 해당 값으로 title을 설정한다.
 * @param {String} url 화면 파일 경로
 * @param {String} pgmId 프로그램코드 - DB에 저장되어있는 프로그램 코드
 * @param {Object} paramObj 화면에 전달할 JSON 데이터 객체
 * @param {Object} option 화면 오픈 옵션
 * @param {String} option.menuType 메뉴타입 ("SP" : 샘플화면)
 * @param {String} option.closable 닫기버튼 보여주기 여부
 * @param {Boolean} option.isHistory Browser History에 기록할 지 여부 (true, false)
 * @returns {Boolean} Main Layout 안에 화면이 오픈 됐는지 여부
 * @hidden N
 * @exception 
 * @example
 * $c.win.openMenu("인사조회","/tmp/tmp01.xml","tmp01.xml");
 */
scwin.openMenu = function (menuNm, url, pgmId, paramObj, option) {
    // client에서 url 숨기기 메뉴일 경우에는 새 창으로 띄우기 적용 
    if ($c.util.isEmpty(url)) {
        $c.win.alert("메뉴에 프로그램이 등록되지 않았습니다.");
        return false;
    } 
    let openAction = "exist";
    let refreshPid = "", menuCode = "",menuCode2 = "", getMId="";
    if (url == "/") {
        const url = document.location.href + "/";
        window.open(url, "", "width=1200, height=700, left=450, top=100");
        return false;
    } else {
        if (!$c.util.isEmpty(pgmId)) {
            if (!/\.(jsp|xml)$/i.test(pgmId)) {
                pgmId += ".jsp";
            } else {
                pgmId = pgmId.replace(/\.xml$/i, ".jsp");
            }
        }
        menuCode = pgmId.replace(/.jsp/g,"").replace(/.xml/g,"") || "";
        let pgmNm = "",mId = "",mParam="",pObj={}, menuSysCd = "", authBypassYn = "";
        const closeCurrentTabYn = !$c.util.isEmpty(option) && (option.closeCurrentTabYn === "Y" || option.closeCurrentTabYn === true);
        if (!$c.util.isEmpty(option) && !$c.util.isEmpty(option.pgmNm)) {
            pgmNm = option.pgmNm;
        }
        if (!$c.util.isEmpty(option) && !$c.util.isEmpty(option.menuId)) {
            mId = option.menuId;
        }
        if (!$c.util.isEmpty(option) && !$c.util.isEmpty(option.sysCd)) {
            menuSysCd = option.sysCd;
        }
        if (!$c.util.isEmpty(option) && option.authBypassYn === "Y") {
            authBypassYn = "Y";
        }

        let mdiTitId = pgmId.replace(/\_/g,"").replace(/\.(xml|jsp)$/i,"");
        if (!$c.util.isEmpty(option) && (!$c.util.isEmpty(option.menuCode) || !$c.util.isEmpty(option.menuCode2))) {
            menuCode = option.menuCode;
            menuCode2 = option.menuCode2;
            refreshPid = menuCode;

            mdiTitId = mdiTitId+menuCode;
            // if(menuCode2) {
            //     mId = menuCode;
            // }

        }

        let parentMenuId = "";
        try {
            if (paramObj != null && typeof paramObj.menuInfo !== "undefined" && paramObj.menuInfo.menuId) {
                parentMenuId = paramObj.menuInfo.menuId;
            }
        } catch (e) {}
        try {
            if (!parentMenuId && typeof $p.getAllParameter === "function") {
                const allParam = $p.getAllParameter();
                if (allParam && allParam.paramData && allParam.paramData.menuInfo && allParam.paramData.menuInfo.menuId) {
                    parentMenuId = allParam.paramData.menuInfo.menuId;
                }
            }
        } catch (e) {}

        let mIdObj = "",openYn="1";
            mIdObj = $c.win.getMainFrame().ds_allMenuList.getMatchedJSON("actPgmId", pgmId, false);

        // 운영에서는 openYn="0" 인 화면은 alert 처리
            try {
               if (scwin.isServerMode() == "prd" && mIdObj.length > 0) {
                // openYn = "1"인 애 찾기
                let openItem = mIdObj.find(item => item.openYn === "1");

                if (!openItem) {
                    $c.win.alert("해당 화면은 현재 점검 및 준비 중 입니다.");
                    return;
                }
            }
            } catch(e) {
                console.log(e);
            }

            if(mId == "") {
                if(mIdObj.length > 0) {
                    mId = mIdObj[mIdObj.length -1].menuId;
                }
            }
        if (mId == "" && parentMenuId) {
            mId = parentMenuId;
        }
        const resolvedMenuId = (mId || parentMenuId || menuCode || "").toLowerCase();
        if (!menuSysCd && resolvedMenuId.indexOf("n") > -1) {
            menuSysCd = "NC";
        }
        try {
            if (!menuSysCd) {
                let authMenuList = [];
                if (mId) {
                    authMenuList = $c.win.getMainFrame().ds_allMenuList.getMatchedJSON("menuId", mId, false);
                }
                if ((!authMenuList || authMenuList.length === 0) && mIdObj && mIdObj.length > 0) {
                    authMenuList = mIdObj;
                }
                if ((!authMenuList || authMenuList.length === 0) && pgmId) {
                    authMenuList = $c.win.getMainFrame().ds_allMenuList.getMatchedJSON("actPgmId", pgmId, false);
                }
                if (authMenuList && authMenuList.length > 0) {
                    menuSysCd = authMenuList[authMenuList.length - 1].sysCd || "";
                }
            }
        } catch (e) {}
        if (!$c.util.isEmpty(option) && !$c.util.isEmpty(option.menuParam)) {
            mParam = option.menuParam.split('&');
            mParam.forEach(param => {
                let [key, value] = param.split('=');
                pObj[key] = value;
            });
        }
        if(paramObj != null && typeof paramObj.menuInfo !== "undefined" && paramObj.menuInfo.menuParam) {
            pObj = paramObj.menuInfo.menuParam;
        }

        const layout = "T";
        let tmpUrl;
        // let menuCodeParm = menuCode;
        let frameMode = '';
        let data = {};
        let closable = true;
        let fixed = false;

        if (url.indexOf("/") !== 0) {
            url = "/" + url;
        }
        url = $c.sbm.getContextPath() + url;

        if ((typeof paramObj !== "undefined") && (paramObj !== null)) {
            data = paramObj;
        }

        data.menuInfo = {
            menuNm: menuNm,
            pgmNm : pgmNm,
            pgmId: pgmId,
            menuId : mId || menuCode,
            sysCd : menuSysCd,
            authBypassYn : authBypassYn,
            refreshPid : refreshPid,
            src: url,
            menuParam : pObj
        };

        if (!$c.util.isEmpty(option) && !$c.util.isEmpty(option.menuType)) {
            data.menuInfo.menuType = option.menuType;
        }

        if (!$c.util.isEmpty(option) && !$c.util.isEmpty(option.closable)) {
            closable = option.closable;
        }

        if (!$c.util.isEmpty(option) && !$c.util.isEmpty(option.fixed)) {
            fixed = option.fixed;
        }
        if (!$c.util.isEmpty(option) && !$c.util.isEmpty(option.openAction)) {
            openAction = option.openAction;
        }

        if (layout == "T") {
            let shouldWriteProgramUseLog = true;
            const callerTabIndex = (function () {
                try {
                    if (!closeCurrentTabYn || $p.top().$p.isPopup()) {
                        return -1;
                    }

                    const mainFrame = $p.main();
                    const currentFrame = $p.getFrame();
                    const tabCount = mainFrame.tac_layout.getTabCount();

                    for (let idx = 0; idx < tabCount; idx++) {
                        const tabFrame = mainFrame.tac_layout.getFrame(idx);
                        if (tabFrame === currentFrame) {
                            return idx;
                        }
                        if (tabFrame && currentFrame && tabFrame.id && currentFrame.id && tabFrame.id === currentFrame.id) {
                            return idx;
                        }
                    }

                    return mainFrame.tac_layout.getSelectedTabIndex();
                } catch (e) {
                    return -1;
                }
            })();

            const closeCallerTabIfNeeded = function (tabId) {
                if (!closeCurrentTabYn || callerTabIndex < 0 || tabId === callerTabIndex) {
                    return tabId;
                }

                try {
                    const mainFrame = $p.main();
                    const callerFrame = mainFrame.tac_layout.getFrame(callerTabIndex);
                    if (!callerFrame || mainFrame.main.closeBeforePage(callerFrame) === false) {
                        return tabId;
                    }

                    mainFrame.tac_layout.deleteTab(callerTabIndex);

                    let targetTabIndex = tabId;
                    if (callerTabIndex < tabId) {
                        targetTabIndex = tabId - 1;
                    }
                    if (targetTabIndex > -1) {
                        mainFrame.tac_layout.setSelectedTabIndex(targetTabIndex);
                    }
                    return targetTabIndex;
                } catch (e) {
                    return tabId;
                }
            };
            const tabObj = {
                closable: closable, // 탭 닫기 기능 제공
                openAction: openAction, // exist 는 기존 탭을 갱신, new 는 항상 새로, select는 동일 id 가 존재하면 선택, last: 기존 tab을 마지막 tab으로 이동후 선택
                label: menuNm
            };

        if (!$c.util.isEmpty(option) && !$c.util.isEmpty(option.addTabIndex)) {
            tabObj.addTabIndex = option.addTabIndex;
        }

            const contObj = {
                frameMode: "pageFrame",
                scope: true,
                src: url,
                alwaysDraw: false,
                title: menuNm,
                dataObject: {
                    type: "json",
                    name: "paramData",
                    data: data
                }
            };

            let uId = $c.data.getMemInfo("userId");
            if(uId && pgmId) {
                let dma = $p.top().dma_mem;
                if (dma !== undefined) {
                    dma.set("userId", uId);
                    dma.set("pgmId", pgmId);
                    dma.set("authMenuId", mId || menuCode);
                    dma.set("authSysCd", menuSysCd || "");
                    dma.set("authBypassYn", authBypassYn || "");
                }

            }

            // tabObj의 openAction의 last값의 동작 특이 사항으로 선택이 되지 않은 경우 선택하는 로직 추가
            if (authBypassYn === "Y" || scwin.isAuthFreePage(url)) {
                return Promise.resolve().then(function () {
                    // return $p.main().tac_layout.addTab(mId || menuCode, tabObj, contObj);
                    return $p.main().tac_layout.addTab(mdiTitId, tabObj, contObj);
                }).then(function (tabId) {
                    return closeCallerTabIfNeeded(tabId);
                }).then(function (tabId) {
                    $p.main().tac_layout.setSelectedTabIndex(tabId);
                    return tabId;
                }).then( function(tabId) {
                    if(!$c.util.isEmpty(option) && typeof option.mdiTitle !== "undefined") {
                        $p.main().tac_layout.setLabelText($p.main().tac_layout.getSelectedTabIndex(), option.mdiTitle)
                    }
                    if (!$c.util.isEmpty(option) && option.isHistory && !$c.util.isEmpty(menuCode)) {
                        $c.win.pushState(data);
                    }
                    scwin.writeProgramUseLog(url, pgmId);
                    return tabId;
                });
            }

            return Promise.resolve().then(function () {
                 return $p.top().scwin.setUserAuth();
            }).then(function (ret) {
                if (ret === false) {
                    shouldWriteProgramUseLog = false;
                    const authFailedUrl = $c.sbm.getContextPath() + "/cm/xml/auth_failed.xml";
                    const authFailedContObj = {
                        frameMode: "pageFrame",
                        scope: true,
                        src: authFailedUrl,
                        alwaysDraw: false,
                        title: menuNm,
                        dataObject: {
                            type: "json",
                            name: "paramData",
                            data: {
                                menuInfo: {
                                    menuNm: menuNm,
                                    pgmNm: menuNm,
                                    pgmId: "auth_failed.jsp",
                                    menuId: mId || menuCode,
                                    refreshPid: refreshPid,
                                    src: authFailedUrl,
                                    menuParam: pObj
                                }
                            }
                        }
                    };
                    // return $p.main().tac_layout.addTab(mId || menuCode, tabObj, authFailedContObj);
                    return $p.main().tac_layout.addTab(mdiTitId, tabObj, authFailedContObj);
                }
                //  return $p.main().tac_layout.addTab(mId || menuCode, tabObj, contObj);
                 return $p.main().tac_layout.addTab(mdiTitId, tabObj, contObj);
            }).then(function (tabId) {
                return closeCallerTabIfNeeded(tabId);
            }).then(function (tabId) {
                $p.main().tac_layout.setSelectedTabIndex(tabId);
                return tabId;
            }).then( function(tabId) {
                if(!$c.util.isEmpty(option) && typeof option.mdiTitle !== "undefined") {
                    $p.main().tac_layout.setLabelText($p.main().tac_layout.getSelectedTabIndex(), option.mdiTitle)
                }
                // history에 화면 전환했던 프로그램 코드 저장
                if (!$c.util.isEmpty(option) && option.isHistory && !$c.util.isEmpty(menuCode)) {
                    $c.win.pushState(data);
                }
                if (shouldWriteProgramUseLog) {
                    scwin.writeProgramUseLog(url, pgmId);
                }
                return tabId;
            });

        } else if (layout == "M") {
            const options = {
                title: menuNm,
                src: url,
                windowTitle: menuNm,
                windowId: menuCode,
                openAction: "selectWindow",
                frameMode: "pageFrame",
                fixed: (fixed === true) ? true : false,
                _closable: (closable === false) ? false : true,
                closeAction: function (title) {
                    const winScope = $p.main().wdc_main.getWindowByUniqueId(this.id);

                    if (winScope.options != undefined && winScope.options._closable === false) {
                        return false;
                    } else {
                        const isOnbeforecloseall = $p.main().wdc_main.getUserData("isOnbeforeCloseAll");

                        if ((typeof isOnbeforecloseall === "undefined") || (isOnbeforecloseall === false)) {
                            const isClose = true;
                            // const isClose = $p.main().main.closeBeforePage(winScope.$p.getFrame());
                            // if (isClose === false) {
                                // $p.main().wdc_main.setFocus($p.main().wdc_main.getSelectedIndex());
                            // }
                            $p.main().wdc_main.setUserData("isOnbeforeCloseAll", false);
                            return isClose;
                        }

                        return true;
                    }
                },
                dataObject: {
                    type: "json",
                    name: "paramData",
                    data: data
                }
            }

            return Promise.resolve().then(function () {
                $p.main().wdc_main.createWindow(options);
                return options;
            }).then(function (options) {
                let winScope = $p.main().wdc_main.getWindow(options.windowId);
                winScope.options = { _closable: options._closable };

                // history에 화면 전환했던 프로그램 코드 저장
                if (!$c.util.isEmpty(option) && option.isHistory && !$c.util.isEmpty(menuCode)) {
                    $c.win.pushState(data);
                }
            });
        } else if (layout == "S") {
            //start 동일메뉴 재오픈 체크
            let curParamData = $p.main().pfm_layout.scope.$p.getParameter("paramData") || {};
            let curMenuInfo = curParamData["menuInfo"];
            if (curMenuInfo){
                let curMenuCd = curMenuInfo["menuCode"];
                if (curMenuCd == menuCode){
                    //이미 열려있는 메뉴면 리턴처리.
                    return false;
                }
            }
            //end
            const isClose = $p.main().main.closeBeforePage($p.main().pfm_layout.getWindow().$p.getFrame());

            if (isClose) {
                const programCd = $p.main().pfm_side.getWindow().dlt_menu.getMatchedColumnData("SRC_PATH", url, "PROGRAM_CD");
                data.menuInfo.programCd = programCd[0];

                // history에 화면 전환했던 프로그램 코드 저장
                if (!$c.util.isEmpty(option) && option.isHistory && !$c.util.isEmpty(menuCode)) {
                    $c.win.pushState(data);
                }

                const param = {
                    dataObject: {
                        type: "json",
                        name: "paramData",
                        data: data
                    }
                };

                return Promise.resolve().then(function () {
                    return $p.main().pfm_layout.setSrc(url, param);
                });
            } else {
                return false;
            }
        }
    }
    return false;
};

/**
 * @method 
 * @name openPopup
 * @description 팝업창을 연다.
 * @param {String} url url 화면경로
 * @param {Array} opts Popup창 옵션
 * @param {String} options.id Popup창 아이디
 * @param {String} options.type 화면 오픈 타입 ("pageFramePopup", "browserPopup")
 * @param {String} options.width Popup창 넓이
 * @param {String} options.height Popup창 높이
 * @param {String} options.popupName useIframe : true시 popup 객체의 이름으로 popup 프레임의 표시줄에 나타납니다.
 * @param {String} options.useIFrame [default : false] true : IFrame 을 사용하는 WebSquare popup / false: window.open 을 사용하는 popup
 * @param {String} options.style Popup의 스타일을 지정합니다. 값이 있으면 left top width height는 적용되지 않습니다.
 * @param {String} options.resizable [default : false]
 * @param {String} options.modal [default : false]
 * @param {String} options.scrollbars [default : false]
 * @param {String} options.title [default : false]
 * @param {String} options.notMinSize [default : false]
 * @param {Object} data 팝업 화면에 전달할 데이터 객체 (type이 pageFramePopup인 경우만 지원)
 * @hidden N
 * @exception 
 * @example
 */
scwin.openPopup = function (url, opts, data, tp) {
    return new Promise(function (resolve, reject) {

        if (typeof opts !== "object") {
            opts = {};
        }

        if ($c.util.isEmpty(data)) {
            data = {};
        }

        if (Array.isArray(data)) {
            data = {data: data};
        }

        // resolve 1회 보장
        let __settled = false;                               
        const __safeResolve = function (v) {                 
            if (__settled) return;
            __settled = true;
            resolve(v);
        };

        _POP_RESOLVE_ = __safeResolve;;
        _POP_CALLBK_ = null;
        if ($c.util.isEmpty(data.callbackFn)) {
            data.callbackFn = function (rtn) {
                if (!$c.util.isEmpty(rtn)) {
                    if (!$c.util.isEmpty(rtn.clickValue)) {
                        resolve(rtn.clickValue);
                    } else {
                        resolve(rtn);
                    }
                } else {
                    resolve(false);
                }
            };
        } else { // X버튼 눌렀을 때 promise가 영원히 pending에 걸리는 문제 해결을 위해 넣은 로직
            // ★CHANGED: 기존 콜백 유지 + Promise도 종료
            const __userCb = data.callbackFn;
            _POP_CALLBK_ = __userCb;

            data.callbackFn = function (rtn) {
                try {
                    if (typeof __userCb === "function") __userCb.call(this, rtn);
                } finally {
                    if (!$c.util.isEmpty(rtn)) {
                        if (!$c.util.isEmpty(rtn.clickValue)) __safeResolve(rtn.clickValue);
                        else __safeResolve(rtn);
                    } else {
                        __safeResolve(false);
                    }
                }
            };
        }

        scwin._openPopup(url, opts, data, tp);

        // X 닫힘에서도 closeAction/콜백이 안 올 수 있으니 “닫힘 감시”로 강제 종료
        try {                                                
            const popupId = opts.id;                          
            if (!popupId) return;

            let existedOnce = false;
            const iv = setInterval(function () {
                // 팝업이 한 번이라도 존재했는지 체크
                const w = $p.getPopupWindow(popupId);
                if (w) existedOnce = true;

                // 한 번 존재했는데 이제 없으면 = 닫힘 (X 포함)
                if (existedOnce && !w) {
                    clearInterval(iv);
                    __safeResolve(false); // X 닫힘은 false로 종료 (async 쪽에서 null 처리하면 됨)
                }

                // 이미 resolve 됐으면 감시 중단
                if (__settled) {
                    clearInterval(iv);
                }
            }, 200);
        } catch (e) {}                                        
    });

};

/**
 * @method 
 * @name _openPopup
 * @description 팝업창을 연다.
 * @param {String} url url 화면경로
 * @param {Array} opt Popup창 옵션
 * @param {String} options.id Popup창 아이디
 * @param {String} options.type 화면 오픈 타입 ("pageFramePopup", "browserPopup")
 * @param {String} options.width Popup창 넓이
 * @param {String} options.height Popup창 높이
 * @param {String} options.popupName useIframe : true시 popup 객체의 이름으로 popup 프레임의 표시줄에 나타납니다.
 * @param {String} options.useIFrame [default : false] true : IFrame 을 사용하는 WebSquare popup / false: window.open 을 사용하는 popup
 * @param {String} options.style Popup의 스타일을 지정합니다. 값이 있으면 left top width height는 적용되지 않습니다.
 * @param {String} options.resizable [default : false]
 * @param {String} options.modal [default : false]
 * @param {String} options.scrollbars [default : false]
 * @param {String} options.title [default : false]
 * @param {String} options.notMinSize [default : false]
 * @param {Object} data 팝업 화면에 전달할 데이터 객체
 * @param {Object} closeActionFunc 팝업이 닫힐 때 실행될 콜백 함수
 * @hidden Y
 * @exception 
 * @example
 */
scwin.normalizePopupProgramId = function (url, popupId, pgmId) {
    const normalizedUrl = (url || "").split("?")[0].split("#")[0];
    const urlFileNm = normalizedUrl.substring(normalizedUrl.lastIndexOf("/") + 1);
    const urlBaseId = urlFileNm.replace(/\.(xml|jsp)$/i, "");
    let normalizedPgmId = pgmId || "";

    if (!normalizedPgmId && popupId) {
        if (/\.(jsp|xml)$/i.test(popupId)) {
            normalizedPgmId = popupId;
        } else if (popupId === urlBaseId) {
            normalizedPgmId = popupId + ".jsp";
        }
    }

    if (!normalizedPgmId) {
        normalizedPgmId = urlFileNm;
    }

    return (normalizedPgmId || "").split("?")[0].split("#")[0].replace(/\.xml$/i, ".jsp");
};

scwin._openPopup = function (url, opt, data, tp) {//debugger;
    let parentPgmId = "";
    const popupPgmId = scwin.normalizePopupProgramId(url, opt.id, opt.pgmId);
    try {
        parentPgmId = $p.getAllParameter().paramData.menuInfo.pgmId;
        parentMenuId = $p.getAllParameter().paramData.menuInfo.menuId;
    } catch(e) {
        parentPgmId = "";
        parentMenuId = "";
    }
    data.menuInfo = {
        src: url,
        pgmId : popupPgmId,
        pFrmId: $p.getFrameId(),
        parentPgmId : parentPgmId,
        parentMenuId : parentMenuId,
        popupName: opt.popupName || "",
        popupTitle: opt.popupTitle || "",
    };

    const _dataObj = {
        type: "json",
        data: data,
        name: "paramData"
    };

    let width = opt.width || 500;
    let height = opt.height || 500;
    opt.type = opt.type || "browserPopup";

    try {
        const deviceWidth = parseFloat($("body").css("width"));
        const deviceHeight = parseFloat($("body").css("height"));

        if (!opt.notMinSize) {
            let borderSize = 4;
            if (opt.type != "browserPopup") {
                borderSize = 4
                if (deviceWidth > 0 && width > deviceWidth) {
                    width = deviceWidth - borderSize; // 팝업 border 고려
                }

                if (deviceHeight > 0 && height > deviceHeight) {
                    height = deviceHeight - borderSize; // 팝업 border 고려
                }

            } else {
                if (window.screen.availHeight <= height) {
                    height = window.screen.availHeight - 100;
                }
            }
        }
    } catch (ex) {
        console.error(ex);
    }

    opt.frameModal = opt.frameModal || "";

    opt.className = opt.frameModal == "frame" ? opt.className ? opt.className + " f_pop" : "f_pop" : "";

    let top, left;

    if (opt.type == "browserPopup") {
        top = Math.floor(((window.screen.availHeight - 50 - $c.num.parseInt(height))) / 2) + (window.screen.availTop || 0) + "px";
        left = Math.floor((window.screen.availWidth - $c.num.parseInt(width)) / 2) + (window.screen.availLeft || 0) + "px";
    } else {
        let frameTop = 0;
        let frameLeft = 0;

        if (opt.frameModal === "frame") {
            frameTop = $p.getFrame().render.getBoundingClientRect().top / 2;
            frameLeft = $p.getFrame().render.getBoundingClientRect().left / 2;
        }

        top = ((document.body.offsetHeight / 2) - ($c.num.parseInt(height) / 2) - frameTop + $(document).scrollTop()) + "px";
        left = ((document.body.offsetWidth / 2) - ($c.num.parseInt(width) / 2) - frameLeft + $(document).scrollLeft()) + "px";

    }

    if (typeof _dataObj.data !== "undefined") {
        if (typeof _dataObj.data.callbackFn == "function") {
            const cbFuncIdx = ++scwin.CB_FUNCTION_MANAGER["cbFuncIdx"];
            const idx = "__close_callback_Func__" + new Date().getTime() + "_" + cbFuncIdx;
            scwin.CB_FUNCTION_MANAGER["cbFuncSave"][$p.id + idx] = _dataObj.data.callbackFn;
            _dataObj.data.callbackFn = $p.id + idx;
        } else if (typeof _dataObj.data.callbackFn === "undefined") {
            _dataObj.data.callbackFn = "";
        } else if (typeof _dataObj.data.callbackFn === "string") {
            _dataObj.data.callbackFn = $p.id + _dataObj.data.callbackFn;
        }
    }

    const options = {
        id: opt.id,
        popupName: opt.popupName || "",
        type: opt.type,
        width: width + "px",
        height: height + "px",
        top: opt.top || top || "140px",
        left: opt.left || left || "500px",
        modal: (opt.modal == false) ? false : true,
        frameModal: opt.frameModal,
        dataObject: _dataObj,
        alwaysOnTop: opt.alwaysOnTop || true,
        useModalStack: (opt.useModalStack == false) ? false : true,
        resizable: (opt.resizable == false) ? false : true,
        useMaximize: opt.useMaximize || false,
        className: opt.className || "",
        scrollbars: true,
        windowDragMove: opt.windowDragMove || true,
        windowMoveType: opt.windowMoveType || "overflow",
        controls : opt.controls || "",
        useControl : opt.useControl || "",
        minVisibleWindowPixel: 20,
        // popupUrl: "../popup" ,
        closeAction: function () {
            let popupWindow = $p.getPopupWindow(this.id);
            if ($p.getPopupWindow(this.id) == undefined) {
                popupWindow = this.getScopeWindow();
            }

            const messageType = $c.data.getParameter("messageType", popupWindow.$p) || "alert";
            const callbackFuncStr = $c.data.getParameter("callbackFn", popupWindow.$p);
            const callbackFunc = $c.util.getCallBackFunction(callbackFuncStr);

            if (typeof callbackFunc === "function") {
                let popup;
                if (popupWindow.$p.isWFramePopup()) {
                    popup = popupWindow.scwin._popup;
                } else {
                    popup = popupWindow.$p.main().scwin._popup
                }

                if (!$c.util.isEmpty(popup) && !$c.util.isEmpty(popup.callbackParam)) {
                    callbackFunc($c.util.getJSON(popup.callbackParam));
                } else {
                    if (messageType === "confirm") {
                        callbackFunc({ clickValue: false });
                    } else {
                        callbackFunc();
                    }
                }
            }
            return true;
        }
        //  , popupUrl: "../popup"
    };

    if (url.indexOf("xml/messageBox.xml") > 0 || scwin.isAuthFreePage(url)) {
        $p.openPopup(url, options);
    } else {
        if (typeof tp !== "undefined" && tp == "ebiz") {
            $p.openPopup(url, options);
            scwin.writeProgramUseLog(url, popupPgmId);
        } else {
            return Promise.resolve().then(function () {
                let uId = $c.data.getMemInfo("userId");
                let pgmId = scwin.normalizePopupProgramId(url, opt.id, opt.pgmId);
                let menuCode="" ,menuSysCd = "";
                menuCode = pgmId.replace(/.jsp/g,"").replace(/.xml/g,"") || "";
                const resolvedMenuId = (menuCode || "").toLowerCase();

                try {
                    if (!menuSysCd && resolvedMenuId.indexOf("n") > -1) {
                        menuSysCd = "NC";
                    }
                    if($c.data.getMemInfo().userHomeClsCd == "FB" || $c.data.getMemInfo().userHomeClsCd == "81") {
                        menuSysCd = "NC";
                    }
                } catch(e) {
                    console.log(e);
                }

                if ($p.isPopup() && !$p.isWFramePopup()) {
                    let mFrm = scwin.getMainFrame();
                    if (uId && pgmId) {
                        let dma = mFrm.dma_mem;
                        if (dma !== undefined) {
                            dma.set("userId", uId);
							dma.set("authSysCd", menuSysCd || "");
                            dma.set("pgmId", pgmId);
                        }
                    }
                    return mFrm.scwin.setUserAuth();
                    // return $p.top().$p.parent().scwin.setUserAuth();
                } else {
                    if(pgmId != 'commonPopup.jsp' && pgmId != 'auth_failed.jsp') {
                        if (uId && pgmId) {
                            let dma = $p.top().dma_mem;
                            if (dma !== undefined) {
                                dma.set("userId", uId);
								dma.set("authSysCd", menuSysCd || "");
                                dma.set("pgmId", pgmId);
                            }
                        }
                        return scwin.getMainFrame().scwin.setUserAuth();
                    }
                }
            }).then(function (ret) {
                if (ret === false) {
                    const authFailedUrl = $c.sbm.getContextPath() + "/cm/xml/auth_failed.xml";
                    const authFailedOptions = Object.assign({}, options, {
                        dataObject: {
                            type: "json",
                            name: "paramData",
                            data: {
                                menuInfo: {
                                    src: authFailedUrl,
                                    pgmId: "auth_failed.jsp",
                                    pFrmId: $p.getFrameId(),
                                    parentPgmId: parentPgmId,
                                    parentMenuId: parentMenuId,
                                    popupName: opt.popupName || ""
                                }
                            }
                        }
                    });
                    return $p.openPopup(authFailedUrl, authFailedOptions);
                }
                $p.openPopup(url, options);
                scwin.writeProgramUseLog(url, popupPgmId);
            });
        }
    }

};

/**
 * @method 
 * @name closePopup
 * @description 팝업창을 닫는다.
 * @param {String} callbackParam 부모 창에 전달한 데이터
 * @param {String} callbackFnStr 콜백 함수 명
 * @hidden N
 * @exception 
 * @example
 */
scwin.closePopup = function (callbackParam, callbackFnStr) {
    if (!$c.util.isEmpty(callbackParam)) {
        $p.getFrame().scope.scwin._popup = {
            callbackParam: callbackParam
        };
    }
    scwin._closePopup($c.win.getPopupId(), $c.str.serialize(callbackParam), callbackFnStr);
};

// TODO :: 아래의 코드는 테스트 완료 후 삭제해야 합니다.
/**
 * @method 
 * @name _closePopup
 * @description 팝업창을 닫는다.
 * @param {String} popId popup창 id로 값이 없을 경우 현재창의 아이디
 * @param {String} callbackParamStr 부모 창에 전달한 데이터
 * @param {String} callbackFnStr 콜백 함수 명
 * @hidden Y
 * @exception 
 * @example
 */
scwin._closePopup = function (popId, callbackParamStr, callbackFnStr) {
    $c.util.setTimeout(
        function () {
            if ($p.isWFramePopup()) {
                $p.closePopup(popId);
            } else {
                let func = $c.util.getCallBackFunction(callbackFnStr);

                if (func) {
                    func($c.util.getJSON(callbackParamStr));
                } else if (opener !== null) {
                    func = opener.$c.util.getCallBackFunction(callbackFnStr);
                    if (func) {
                        func($c.util.getJSON(callbackParamStr));
                    }
                }
                $w.closePopup();
            }
        },
        { delay: 10, key: "closePopup" + (Math.random() * 16).toString().replace(".", "") }
    );
};


/**
 * @method 
 * @name closeAllPopup
 * @description 현재 오픈된 전체 팝업창을 닫는다.
 * @hidden N
 * @exception 
 * @example
$c.win.closeAllPopup();
 */
scwin.closeAllPopup = function () {
    // WebSquare.uiplugin.popup.popupList 속성은 엔진 내 비공개 속성으로 공통에서만 제한적으로 사용함(업무 화면 소스 사용 금지)
    const popupList = WebSquare.uiplugin.popup.popupList;
    for (let idx = 0; idx < popupList.length; idx++) {
        $p.closePopup(WebSquare.uiplugin.popup.popupList[idx].id);
    }
};

/**
 * @method 
 * @name isPopup
 * @description 현재 화면이 팝업 인지의 여부를 반환한다.
 * @returns {Boolean} 팝업여부(팝업인 경우 true, 팝업이 아닌 경우 false)
 * @hidden N
 * @exception 
 * @example
if ($c.win.isPopup()) {
    $c.win.alert("현재 화면은 팝업입니다.");
};
 */
scwin.isPopup = function () {
    return isPopup($p);

    function isPopup(scope) {
        if (scope.isPopup()) {
            return true;
        } else if (scope.top().$p.getFrameId() === scope.getFrameId()) {
            return false;
        } else {
            return isPopup(scope.parent().$p);
        }
    }
};


/**
 * @method 
 * @name messageBox
 * @description 메세지 팝업을 호출한다.
 * @param {String} messageType 팝업창 타입 (alert || confirm)
 * @param {String} messageStr 메시지
 * @param {String} closeCallbackFncName 콜백 함수명
 * @param {Object} opts messageBox의 callBackParam 등의 정보가 있는 객체
 * @hidden N
 * @exception 
 * @example
//alert창을 띄울 경우
scwin.callback = function(){
    console.log("콜백 함수입니다.");
};
$c.win.messageBox($p, "alert", "보낼 메시지", "callback");

//confirm창을 띄울 경우
scwin.callback = function(){
    console.log("콜백 함수입니다.");
};
$c.win.messageBox($p, "confirm", "보낼 메시지", "callback");
 */
scwin.messageBox = function (messageType, messageStr, closeCallbackFncName, opts) {
    messageStr = messageStr || "";
    messageType = messageType || "alert";
    let popId = messageType || "tmp";

    popId = popId + (Math.random() * 16).toString().replace(".", "");

    if (typeof opts.callBackParam !== "object") {
        opts.callBackParam = {};
    }

    let sysMsg = "";

    if ($c.util.isArray(messageStr)) {
        sysMsg = $c.data.getMessage(messageStr);
        if (typeof sysMsg === "string" && sysMsg != "") {
            messageStr = sysMsg;
        } else {
            messageStr = "";
        }
    } else {
        sysMsg = $c.data.getMessage(messageStr);
        if (typeof sysMsg === "string" && $c.util.isEmpty(sysMsg) === false) {
            messageStr = sysMsg;
        }
    }

    const data = {
        "message": messageStr,
        "callbackFn": closeCallbackFncName,
        "messageType": messageType,
        "id": popId,
        "callBackParam": opts.callBackParam
    };

    const options = {
        id: popId,
        popupName: messageType == "alert" ? $c.data.getMessage(MSG_CM_00046) : $c.data.getMessage(MSG_CM_00047),
        width: 380,
        height: 350,
        frameModal: "top",
        type : "pageFramePopup",
        className: "messagebox"
    };

    $c.win.openPopup("/cm/xml/messageBox.xml", options, data);
};

