};

/**
 * @method 
 * @name isAdmin
 * @description 로그인한 사용자가 시스템 관리자 인지의 여부를 반환한다.
 * @hidden N
 * @exception 
 * @example
 */
scwin.isAdmin = function () {
    const isAdmin = $p.main().pfm_side.getWindow().dma_defInfo.get("IS_ADMIN");

    if (isAdmin === "Y") {
        return true;
    } else {
