/**
 * @method
 * @name extension
 * @description 해당 그룹의 그리드, 트리를 확대한다
 * @param {string} grp desc
 * @returns
 * @hidden N
 * @exception
 * @example
 */
scwin.initNum = [];

scwin.extension = function (grp) {
    if (!$c.util.isEmpty(grp)) {
        let objArr = $c.util.getChildren(grp, {
            includePlugin: "gridView treeview",
            recursive: true
        });

        for (var i in objArr) {
            if (objArr[i].getPluginName() == "treeview") {
                var tH = parseInt(objArr[i].getStyle("height"));
                objArr[i].setStyle("height", tH + 50 + "px");
            } else if (objArr[i].getPluginName() == "gridView") {//debugger;

                if(typeof objArr[i].options.initRowNumCnt !== "undefined" && objArr[i].options.initRowNumCnt > 0) {
                    // objArr[i].options.initFixedHeightByRowNum = objArr[i].options.initRowNumCnt;
                    // objArr[i].options.visibleRowNum = '';
                } 
                // objArr[i].options.visibleRowNumFix = "false";

                // var rNum = objArr[i].getVisibleRowNum();
                var tNum = objArr[i].getRowCount();
                // var curNum = objArr[i].getDrawCount();
                var curNum = objArr[i]._getDrawedRowCount();
                scwin.initNum[objArr[i]] = scwin.initNum[objArr[i]] || parseInt(objArr[i].options.initRowNumCnt);

                let allCnt = parseInt(tNum + (objArr[i]._getExcelSubtotalData().split("\",\"").length / objArr[i].getTotalCol()));

                // if (tNum > scwin.initNum[objArr[i]] && tNum > curNum) {

                if(curNum >= allCnt) {
                    continue;
                    // objArr[i].setVisibleRowNum(allCnt);
                }else if (allCnt > curNum) {
                    // objArr[i].setTopRowIndex(curNum);
                    objArr[i].setVisibleRowNum(curNum + 5);
                }
            }
        }
    }
};

/**
 * @method
 * @name reduction
 * @description 해당 그룹의 그리드, 트리를 축소한다(visibleRowNum 버젼)
 * @param {string} grp desc
 * @returns
 * @hidden N
 * @exception
 * @example
 */
scwin.reduction = function (grp) {
    if (!$c.util.isEmpty(grp)) {
        let objArr = $c.util.getChildren(grp, {
            includePlugin: "gridView treeview",
            recursive: true
        });

        for (var i in objArr) {
            if (objArr[i].getPluginName() == "treeview") {
                var tH = parseInt(objArr[i].getStyle("height"));
                if (tH > 100) {
                    objArr[i].setStyle("height", tH - 50 + "px");
                }
            } else if (objArr[i].getPluginName() == "gridView") {//debugger;

                if(typeof objArr[i].options.initRowNumCnt !== "undefined" && objArr[i].options.initRowNumCnt > 0) {
                    // objArr[i].options.initFixedHeightByRowNum = objArr[i].options.initRowNumCnt;
                    // objArr[i].options.visibleRowNum = '';
                } 
                // objArr[i].options.visibleRowNumFix = "false";

                var tNum = objArr[i].getRowCount();
                // var curNum = objArr[i].getDrawCount();
                var curNum = objArr[i]._getDrawedRowCount();
                scwin.initNum[objArr[i]] = scwin.initNum[objArr[i]] || parseInt(objArr[i].options.initRowNumCnt);

                // if (tNum > 0 && scwin.initNum[objArr[i]] + curNum > tNum) {
                // if(curNum == tNum && scwin.initNum[objArr[i]] > tNum) {
                // if(curNum < 1 && scwin.initNum[objArr[i]] > tNum) {
                if(curNum <= 1 ) {
                    continue;
                } else if (tNum > 0 ) {
                    let visibleCnt = curNum - 5 > 0 ? (curNum - 5) : 1;
                    objArr[i].setVisibleRowNum(visibleCnt);
                } 
            }
        }
    }
};

/**
 * @method
 * @name getGrid
 * @description 그룹에 포함된 그리드 객체 가져오기
