            }
        }
    }
    return ret;
};

/**
 * @method
 * @name getGridSetting
 * @description 그리드 개인화 초기셋팅
 * @param {string} grd desc
 * @param {string} opts desc
 * @returns
 * @hidden N
 * @exception
 * @example
 */
scwin.getGridSetting = async function (grd, opts) {
    let grdObj = (typeof grd == 'object') ? grd : (typeof grd === 'string') ? $c.gus.object(grd) : grd;
    let gridId = grdObj.id;
    let gridOrgId = grdObj.org_id;
    let userId = $c.data.getMemInfo("userId");
    let pgmId = "";
    // let pgmId = scwin._getPgmId(grdObj.getScopeWindow());
    pgmId = $p.parent().$p.getFrame().getSrc();

    if(pgmId != "") {
        pgmId = pgmId.substring(pgmId.lastIndexOf("/")+1).replace(".xml",".jsp");
    } else {
        pgmId = scwin.__getPgmId(grdObj.getScopeWindow());
    }        
    pgmId = pgmId.substring(pgmId.lastIndexOf("/")+1).replace(".xml",".jsp");

    // pgmId를 못가져오는 화면이 있어 추가
    if (!pgmId) {
        const contentsArr = $p.top().tac_layout.contentsArr;
        const selectedTabIndex = $p.top().tac_layout.getSelectedTabIndex();
        pgmId = contentsArr[selectedTabIndex]?.src;
    }


    let dmSearchSet = $c.gus.object("dma_dataPrivate");
    // if(!dmSearchSet) {	 		
    var jsonData = ["method", "pgmId", "gridId"];
    dmSearchSet = $c.data.createDataMap("dma_dataPrivate", jsonData);
    // }

    dmSearchSet.setJSON({ "method": "select", "pgmId": pgmId, "gridId": gridOrgId });

    const gridSetOption = {
        id: "sbm_getGridSet",
        action: "/GridPrivateService",
        ref: "data:json,dma_dataPrivate",
        processMsg: "none"
    };

    let res = await $c.sbm.executeDynamic(gridSetOption);
    if (res.responseJSON.result == "OK") {

        var rtData = res.responseJSON.gridSetCtnt;
        if (rtData != null) {
            // $p.top().scwin.gridSetArr[usrId+pgmId+gridOrgId] = rtData;
            if (rtData.columnOrderIdx) {
                if (!grdObj.setColumnOrder(JSON.stringify(rtData.columnOrderIdx).replace(/(\[)|(\])/g, ""))) {
                   // return;
                }
            }

            if (rtData.fixedCol && rtData.fixedCol > 0) {
            //    grdObj.setFixedColumn(rtData.fixedCol);
            }

            if (rtData.columnOrderIdx && rtData.hiddenList) {
                for (var key in rtData.hiddenList) {
                    grdObj.setColumnVisible(rtData.columnOrderIdx[key], !rtData.hiddenList[Number(key) + grdObj.defaultColCnt]);
                }
            }

        }
    }


};

/**
 * @method
 * @name gridSetting
 * @description 그리드 개인화 셋팅
 * @param {string} grd desc
 * @param {string} btnId desc
 * @returns
 * @hidden N
 * @exception
 * @example
 */
scwin.gridSetting = async function (grd,flag,moveFlag) {//debugger;
    try {
        let gridObj = (typeof grd == 'object') ? grd : (typeof grd === 'string') ? $c.gus.object(grd) : grd;
        let gridId = gridObj.id;
        let gridOrgId = gridObj.org_id;
        let userId = $c.data.getMemInfo("userId");
        // let pgmId = scwin._getPgmId(gridObj.getScopeWindow());
        let pgmId = "";

        if(typeof moveFlag !== "undefined" && moveFlag == "colMove") {
            if($p.getFrame().scope_obj !== null) {
                pgmId = $p.getFrame().scope_obj.getSrc();
            }
        } else {
            if($p.parent().$p.getFrame().scope_obj !== null) {
                pgmId = $p.parent().$p.getFrame().scope_obj.getSrc();
            }
        }
        if(pgmId != "") {
            pgmId = pgmId.substring(pgmId.lastIndexOf("/")+1).replace(".xml",".jsp");
        } else {
            pgmId = scwin.__getPgmId(gridObj.getScopeWindow());
        }        
        pgmId = pgmId.substring(pgmId.lastIndexOf("/")+1).replace(".xml",".jsp");

        // pgmId를 못가져오는 화면이 있어 추가
        if (!pgmId) {
            const contentsArr = $p.top().tac_layout.contentsArr;
            const selectedTabIndex = $p.top().tac_layout.getSelectedTabIndex();
            pgmId = contentsArr[selectedTabIndex]?.src;
        }

        if (!pgmId) {
            $c.win.alert("pgmId 가 등록되지 않았습니다");
            return;
        }
        let dmaSetSave = $c.gus.object("dma_dataPrivate");

        // if(!dmaSetSave) {				
        let jsonColumn = ["pgmId", "gridId", "method", "gridSetCtnt"];
        dmaSetSave = $c.data.createDataMap("dma_dataPrivate", jsonColumn);
        // }

        let jsonData = {
            pgmId: pgmId,
            method: "save",
            gridSetCtnt: JSON.stringify({
                "columnOrderIdx": gridObj.getColumnOrder(),
                "colwidthList": gridObj.colWidthList,
                "hiddenList": gridObj.hiddenList,
                "fixedCol": parseInt(gridObj.getFixedColumnLastIndex(false)),
                "initColwidthList": gridObj.colWidthList,
                "initColumnOrderIdx": gridObj.getColumnOrder(),
                "initHiddenList": gridObj.hiddenList,
                "initFixedCol": parseInt(gridObj.getFixedColumnLastIndex(false))
            }),
            gridId: gridOrgId
        };

        dmaSetSave.setJSON(jsonData);

        const gridSetOption = {
            id: "sbm_gridSetSave",
            action: "/GridPrivateService",
            ref: "data:json,dma_dataPrivate",
            isProcessMsg: false
        };
        let res = await $c.sbm.executeDynamic(gridSetOption);
        if (res.responseJSON.result == "OK") {
            if(typeof flag !== "undefined" && flag == "init") {
                $c.win.alert("개인화 정보가 초기화되었습니다.");
            } else {
                $c.win.alert("개인화 등록이 완료 되었습니다.");
            }
            return;
        }


    } catch (e) {
        $p.log("[$c.win.gridSetting] Exception :: ", e);
    }
};

scwin._chkCnt = 0;
scwin.__getPgmId = function (obj) {
    try {
        if (scwin._chkCnt > 8) {
            scwin._chkCnt = 0;
            return "";
        }

        let scopeApi = null;
        if (obj && obj.$p) {
            scopeApi = obj.$p;
        } else if (obj && obj.scope && obj.scope.$p) {
            scopeApi = obj.scope.$p;
        }

        if (!scopeApi || typeof scopeApi.getParameter !== "function") {
            scwin._chkCnt = 0;
            return "";
        }

        const paramData = scopeApi.getParameter("paramData");
        if (paramData && paramData.menuInfo) {
            scwin._chkCnt = 0;
            return paramData.menuInfo.refreshPid || paramData.menuInfo.pgmId || "";
        }

        let parentObj = null;
        if (typeof scopeApi.parent === "function") {
            parentObj = scopeApi.parent();
        }

        if (!parentObj || parentObj === obj) {
            scwin._chkCnt = 0;
            return "";
        }

        scwin._chkCnt++;
        return scwin.__getPgmId(parentObj);
    } catch (e) {
        scwin._chkCnt = 0;
        console.log(e);
        return "";
    }
}

scwin._getPgmId = function (obj) {
    return scwin.__getPgmId(obj);
};

/**
 * @method
 * @name setAddTab
 * @description 탭을 추가한다
 * @param {string} tabObj 탭 컨트롤 아이디
 * @param {string} param2 desc
 * @returns
 * @hidden N
 * @exception
 * @example
 */
scwin.setAddTab = function (tabCont, opts) {
    let tabConObj = $c.gus.object(tabCont);
    var opts = opts || {};

    let tabId = opts.tabId,
        url = opts.url,
        menuNm = opts.menuNm,
        data = opts.data;

    const tabObj = {
        closable: true, // 탭 닫기 기능 제공
        openAction: "select", // exist 는 기존 탭을 갱신, new 는 항상 새로, select는 동일 id 가 존재하면 선택, last: 기존 tab을 마지막 tab으로 이동후 선택
        label: menuNm
    };

    const contObj = {
        frameMode: "pageFrame",
        scope: true,
        src: url,
        alwaysDraw: false,
        title: menuNm,
        dataObject: {
            type: "json",
            name: "paramData",
            data: data
        }
    };

    // tabObj의 openAction의 last값의 동작 특이 사항으로 선택이 되지 않은 경우 선택하는 로직 추가
    return Promise.resolve().then(function () {
        return tabConObj.addTab(tabId, tabObj, contObj);
    }).then(function (tabId) {
        tabConObj.setSelectedTabIndex(tabId);
        return tabId;
    });
};

/**
 * @method
 * @name gridSetPopUp
 * @description 그리드 정보를 불러와 그리드 setting 화면 show/hide
 * @param {string} grdObj desc
 * @param {string} btnId desc
 * @returns
 * @hidden N
 * @exception
 * @example
 */
scwin.gridSetPopUp = function (grdObj, btnId) {
    try {
        obj = $c.gus.object("setting");
        // let pgmId = $p.parent().$p.getAllParameter().paramData.menuInfo.pgmId;
        let pgmId = "";
        if($p.top().$p.isPopup()) {
            let pObj = _getParam($p.parent());
            pgmId = pObj["menuInfo"].pgmId;
        } else {
            // pgmId = scwin._getPgmId(grdObj.getScopeWindow());
            pgmId = $p.parent().$p.getFrame().getSrc();
            pgmId = pgmId.substring(pgmId.lastIndexOf("/")+1).replace(".xml",".jsp");
        }

        function _getParam(f) {
            if(typeof f.$p.getParameter("paramData") !== "undefined") {
                return f.$p.getParameter("paramData");
            } else {
                return _getParam(f.$p.parent());
            }
        }
        // await scwin.getGridSetting(grdObj);

        obj.scope.scwin._gridSetPopUp(grdObj, btnId);
    } catch (e) {

        var pobj = scwin._grdSetInitalizer(grdObj, btnId);
        pobj.then(function (wfmObj) {
            wfmObj.getWindow().scwin._gridSetPopUp(grdObj, btnId);
        });
        // console.log("[scwin.gridSetPopUp] Exception :: "+ e);
        //$p.setTimeout(function() { scwin._gridSetPopUp(grdObj,btnId); }, 200);
    }
};

/**
 * @method
 * @name _grdSetInitalizer
 * @description grid setting 팝업을 생성 
 * @param
 * @returns
 * @hidden N
 * @exception
 * @example
 */
scwin._grdSetInitalizer = function (grdArea,btnId) {
    var wfm_makeForm = $c.gus.object("setting");
    if (typeof wfm_makeForm === "undefined") {
        scwin.gridSettingsClose();

        var pObj = $c.util.createComponent("setting", "wframe", {
            src: "/cm/xml/userFilter.xml"
        // }, WebSquare.getBody());
        }, $p.getComponentById($p.getComponentById(btnId).parentControl.id));
        pObj = pObj.then(function (wfmObj) {
            wfmObj.setEventPause("", true);
            return wfmObj;
        });
        return pObj
    }
};

/**
 * @method
 * @name gridSettingsClose
 * @description 개인화 팝업을 닫는다
 * @param
 * @returns
 * @hidden N
 * @exception
 * @example
 */
scwin.gridSettingsClose = function () {
    try {
        $(document).mouseup(function (e) {
            $('.pop_ty1').each(function () {
                if ($(this).css('display') !== 'none') {
                    var l_position = $(this).offset();
                    l_position.right = parseInt(l_position.left) + parseInt($(this).outerWidth());
                    l_position.bottom = parseInt(l_position.top) + parseInt($(this).outerHeight());

                    if ((l_position.left <= e.pageX && e.pageX <= l_position.right) && (l_position.top <= e.pageY && e.pageY <= l_position.bottom)) {
                    } else {
                        $(this).hide("fast");
                    }
                }
            });
        });
    } catch (e) {
        console.log("[$c.win.gridSettingsClose] Exception :: " + e);
    }
}
