    let frm;
    let frame = $p.getFrame();
    if (typeof $p.top().tac_layout === "undefined") {
        let darkYn = $c.data.getMemInfo("darkmodeYn");

        let topFrame = scwin.getMainFrame();
        if ($p.top().$p.isPopup() && !$p.top().$p.isWFramePopup()) {
            frame = WebSquare.getBody();
            if (darkYn == "1") {
                if (!frame.hasClass("dark")) {
                    frame.addClass("dark");
                }
            }
            if($p.getOptions().className) {
                frame.addClass($p.getOptions().className);
            }
        }
        frame.CREATE_AUTH = topFrame.scwin.globalVal.CREATE_AUTH;
        frame.RETRIEVE_AUTH = topFrame.scwin.globalVal.RETRIEVE_AUTH;
        frame.UPDATE_AUTH = topFrame.scwin.globalVal.UPDATE_AUTH;
        frame.DELETE_AUTH = topFrame.scwin.globalVal.DELETE_AUTH;
        frame.PRINT_AUTH = topFrame.scwin.globalVal.PRINT_AUTH;
        frame.EXCEL_AUTH = topFrame.scwin.globalVal.EXCEL_AUTH;
    } else {

        if(location.host.indexOf("ebiz.") > -1) {
            frame.CREATE_AUTH = $p.top().$p.parent().scwin.globalVal.CREATE_AUTH;
            frame.RETRIEVE_AUTH = $p.top().$p.parent().scwin.globalVal.RETRIEVE_AUTH;
            frame.UPDATE_AUTH = $p.top().$p.parent().scwin.globalVal.UPDATE_AUTH;
            frame.DELETE_AUTH = $p.top().$p.parent().scwin.globalVal.DELETE_AUTH;
            frame.PRINT_AUTH = $p.top().$p.parent().scwin.globalVal.PRINT_AUTH;
            frame.EXCEL_AUTH = $p.top().$p.parent().scwin.globalVal.EXCEL_AUTH;
        } else {            
            frame.CREATE_AUTH = $p.top().scwin.globalVal.CREATE_AUTH;
            frame.RETRIEVE_AUTH = $p.top().scwin.globalVal.RETRIEVE_AUTH;
            frame.UPDATE_AUTH = $p.top().scwin.globalVal.UPDATE_AUTH;
            frame.DELETE_AUTH = $p.top().scwin.globalVal.DELETE_AUTH;
            frame.PRINT_AUTH = $p.top().scwin.globalVal.PRINT_AUTH;
            frame.EXCEL_AUTH = $p.top().scwin.globalVal.EXCEL_AUTH;
        }
    }

    let objBtn = "", tmpFrm = [], tmpObjBtn = [];
    let fIdx = "",subTabCnt =0;

	if(frame.options.pluginName == "pageFrame") {
		tmpFrm = $c.util.getChildren($p, frame, {
			includePlugin: "tabControl",
			recursive: true
		});
		if(tmpFrm.length > 0) {
/*
            objBtn = $c.util.getChildren(frame, {
				includePlugin: "trigger anchor button",
			    excludeInnerComp: true, 
				recursive: true
			});
*/
            objBtn = $c.util.getChildren(frame, {
				includePlugin: "trigger anchor button",
			    // excludeInnerComp: true, 
				recursive: true
			});
            let allBtnBbj = [];
            for(var idx in tmpFrm) {
                var subContArr = tmpFrm[idx].contentsArr;
                for(var idx1 =0; idx1 < subContArr.length; idx1++) {
                    if(subContArr[idx1].src != "" ) {
                        tmpObjBtn= $c.util.getChildren($p,tmpFrm[idx].getChildren()[idx1],{ includePlugin: "trigger anchor button",recursive: true });
                        if(tmpObjBtn.length > 0) {
                            for(var idx2 in tmpObjBtn) {
                                allBtnBbj.push(tmpObjBtn[idx2].id);
                            }
                        }
                    }
                }
            }
            objBtn = objBtn.filter((e) => !allBtnBbj.includes(e.id));

		} else {
			objBtn = $c.util.getChildren(frame, {
				includePlugin: "trigger anchor button",
				recursive: true
			});
		}

	} else {
		objBtn = $c.util.getChildren(frame, {
            includePlugin: "trigger anchor button",
            excludePlugin: "tabControl",
			// excludeInnerComp: true,
            recursive: true
        });
	}

    frame.ctrlBtn = [];
    frame.bCreate = null;
    frame.bUpdate = null;
    frame.bSave = null;
    frame.bDelete = null;
    frame.bCreate2 = null;
    frame.bUpdate2 = null;
    frame.bSave2 = null;
    frame.bDelete2 = null;

    for (let k = 0; k < objBtn.length; k++) {
        // 버튼 권한처리
        if (typeof objBtn[k].options !== "undefined" && typeof objBtn[k].options.userAuth !== "undefined" && $c.gus.cfCheckAuth(objBtn[k].options.userAuth) == false) {
            $c.gus.cfEnableObj(objBtn[k], false);
        }
        // 제어 대상 버튼을 배열에 저장
        if (typeof objBtn[k].options !== "undefined") {
            if (objBtn[k].options.objType == "ctrlBtn") {
                frame.ctrlBtn.push(objBtn[k].id);
            }

            switch (objBtn[k].options.objType) {
                // 신규 버튼
                case 'bCreate': frame.bCreate = objBtn[k].id; break;
                // 수정 버튼
                case 'bUpdate': frame.bUpdate = objBtn[k].id; break;
                // 저장 버튼
                case 'bSave': frame.bSave = objBtn[k].id; break;
                // 삭제 버튼
                case 'bDelete': frame.bDelete = objBtn[k].id; break;
                // 신규 버튼2
                case 'bCreate2': frame.bCreate2 = objBtn[k].id; break;
                // 수정 버튼2
                case 'bUpdate2': frame.bUpdate2 = objBtn[k].id; break;
                // 저장 버튼2
                case 'bSave2': frame.bSave2 = objBtn[k].id; break;
                // 삭제 버튼2
                case 'bDelete2': frame.bDelete2 = objBtn[k].id; break;
            }
        }
    }

    const objArr = $c.util.getChildren(frame, {
        excludePlugin: "body calendar group textbox output calendar image span tabControl",
        // excludeInnerComp: true,
        recursive: true
    });

    frame.key = [];
    frame.data = [];
    for (let i = 0; i < objArr.length; i++) {
        switch (objArr[i].getPluginName()) {
            case "input":
            case "inputCalendar":
            case "autoComplete":
            case "radio":
            case "checkbox":
            case "textarea":
            case "secret":
            case "selectbox":
                if (typeof objArr[i].options !== "undefined" && objArr[i].options.objType == "key") {
                    frame.key.push(objArr[i].id);
                } else if (typeof objArr[i].options !== "undefined" && objArr[i].options.objType == "data") {
                    frame.data.push(objArr[i].id);
                }
                break;
        }

    }
};

/**
 * @method
 * @name getMainFrame
 * @description 팝업에서 메인 프레임 찾을때 사용
 * @param {string} p desc
 * @returns
 * @hidden N
 * @exception
 * @example
 */
scwin.getMainFrame = function (p) {
    let frm = p || $p.top();

    if (typeof frm.tac_layout !== "undefined") {
        return frm;
    } else {

        if (typeof frm.$p.parent().tac_layout !== "undefined") {
            return frm.$p.parent().$p.top();
        } else {
            return scwin.getMainFrame(frm.$p.parent());
        }

    }
};

/**
 * @method
 * @name sKeyInit
 * @description desc
 * @param {string} complexKey 복합키
 * @param {string} lastKey 최종키
 * @param {string} fn 실행함수
 * @returns
 * @hidden N
 * @exception
 * @example
 */
scwin.sKeyInit = function (complexKey, lastKey, fn) {//debugger;
    try {
        let menuInfo = "";
        if ($p.getFrame().getPluginName() == "wframe") {
            menuInfo = $c.data.getParameter(undefined, $p.parent().$p).menuInfo;
        } else {
            menuInfo = $c.data.getParameter().menuInfo;
        }

        let pgmId = menuInfo.pgmId || "";

        let jsonData = {
            PROGRAM_CD: pgmId,
            COMPLEX_KEY: complexKey,
            LAST_KEY: lastKey.toUpperCase(),
            EVENT_NAME: fn
        };
        scwin.getMainFrame().dlt_shortcutList.setJSON([jsonData], true);
    } catch (e) {
        console.log(e);
    }

};

/**
 * @method
 * @name setBtnAuth
 * @description 버튼 권한 셋팅
 * @param {Object} obj desc
 * @returns
 * @hidden N
 * @exception
 * @example
 */
scwin.setBtnAuth = function (obj) {
    if (typeof obj === "string") return;

    if (obj) {
        let frame = $p.getFrame();
        if ($p.top().$p.isPopup() && !$p.top().$p.isWFramePopup()) {
            frame = WebSquare.getBody();
        }

        if (typeof $p.top().tac_layout === "undefined") {
            let topFrame = scwin.getMainFrame();

            frame.CREATE_AUTH = obj.CREATE_AUTH || topFrame.scwin.globalVal.CREATE_AUTH;
            frame.RETRIEVE_AUTH = obj.RETRIEVE_AUTH || topFrame.scwin.globalVal.RETRIEVE_AUTH;
            frame.UPDATE_AUTH = obj.UPDATE_AUTH || topFrame.scwin.globalVal.UPDATE_AUTH;
            frame.DELETE_AUTH = obj.DELETE_AUTH || topFrame.scwin.globalVal.DELETE_AUTH;
            frame.PRINT_AUTH = obj.PRINT_AUTH || topFrame.scwin.globalVal.PRINT_AUTH;
            frame.EXCEL_AUTH = obj.EXCEL_AUTH || topFrame.scwin.globalVal.EXCEL_AUTH;

        } else {
            frame.CREATE_AUTH = obj.CREATE_AUTH || $p.top().scwin.globalVal.CREATE_AUTH;
            frame.RETRIEVE_AUTH = obj.RETRIEVE_AUTH || $p.top().scwin.globalVal.RETRIEVE_AUTH;
            frame.UPDATE_AUTH = obj.UPDATE_AUTH || $p.top().scwin.globalVal.UPDATE_AUTH;
            frame.DELETE_AUTH = obj.DELETE_AUTH || $p.top().scwin.globalVal.DELETE_AUTH;
            frame.PRINT_AUTH = obj.PRINT_AUTH || $p.top().scwin.globalVal.PRINT_AUTH;
            frame.EXCEL_AUTH = obj.EXCEL_AUTH || $p.top().scwin.globalVal.EXCEL_AUTH;
        }
    }
};

/**
 * @method
 * @name setHolidayS
 * @description 스케쥴달력 공휴일 설정
 * @param {string} date 날짜(년,월)
 * @returns
 * @hidden N
 * @exception
 * @example
 */
scwin.setHolidayS = function (date) {//debugger;
    if ($c.gus.cfIsNull(date)) return;
    let chkDate = "";
    let tFrm = $c.win.getMainFrame($p);
    let holidayArr = tFrm.dlt_holiday.getMatchedJSON("holiday", date.substring(0, 6), false);
    for (let idx in holidayArr) {
        chkDate = holidayArr[idx].holiday.substring(0, 4) + "-" + holidayArr[idx].holiday.substring(4, 6) + "-" + holidayArr[idx].holiday.substring(6, 8);
        $('td').find("[data-date='" + chkDate + "']").css("color", "red");
    }
};

/**
 * @method
 * @name chUpper
 * @description 소문자를 대문자로 변경
 * @param {object} e 영문자
 * @returns
 * @hidden N
 * @exception
 * @example
 */
scwin.chUpper = function (e) {
    let obj = $p.getComponentById(e.target.id);
    if(e.keyCode > 64 && e.keyCode < 91) {
        obj.setValue(e.target.value.toUpperCase());
    } 

};

