/**
 * @method
 * @name grdDupValid
 * @description 그리드내 컬럼의 중복 여부 체크
 * @param {object} grdID 그리드 아이디
 * @param {object} objColID 그리드 컬럼명
 * @returns
 * @hidden N
 * @exception
 * @example
 */
scwin.grdDupValid = async function (grdID, objColID) {
    let grdObj = $c.gus.object(grdID);
    if(typeof grdObj === "undefined") {
        $c.win.alert("그리드 아이디가 존재하지 않습니다.");
        return;
    }
    let colObj = $c.gus.object(objColID);
    if(typeof colObj === "undefined" || colObj.length < 1) {
        $c.win.alert("중복 체크할 컬럼정보가 존재하지 않습니다.");
        return;
    }
    let hVal="", tHval="",gridNm="";
    gridNm = grdObj.options.gridName ?? "";
    try {
        // alert 출력을 위해서 헤더 정보값을 만든다
        for(let idx in colObj) {
            hVal = grdObj.getHeaderValue(grdObj.getHeaderID(grdObj.getColumnIndex(colObj[idx]))) || "이름없음";
            tHval = tHval + ", "+hVal;
        }
        // 데이터 중복 체크
        let colData,dupIdx,dupCol;
        for(let idx in colObj) {
            colData = grdObj.getColData(colObj[idx]);

            const result = {};
            let dupRt = false;
            colData.forEach((value, key) => { 
                result[value] = (result[value] || 0)+1; 
                if(result[value] > 1) {
                    dupIdx = key;
                    dupCol = colObj[idx];
                    dupRt = true;
                    return false;
                }
            });
            if(dupRt) break;
        }
        if(typeof dupIdx !== "undefined") {
            await $c.win.alert(gridNm +" "+dupIdx +"번째 "+tHval+"은(는) 중복될 수 없습니다");
            $p.setTimeout(function() {
                grdObj.setFocusedCell(dupIdx, dupCol,true);
                return false;
            }, {delay : 50})
            return;
        } else {
            return true;
        }
    } catch(e) {
        console.log(e);
    }

};

