/**
 * @method
 * @name getEventList
 * @description desc
 * @param {object} grid 그리드명
 * @param {object} eventNm 이벤트명
 * @returns
 * @hidden N
 * @exception
 * @example
 */
scwin.getEventList = function (grid, eventNm) {
    try {
        let grd = $c.gus.object(grid);
        let evCnt = 0;
        let ret = false;

        if(grd.getPluginName() == "gridView" ) {
            let grdEvList = grd.userEventList ;   
            for(var idx in grdEvList) {
                if(eventNm) {
                    if(grdEvList[idx].name == eventNm) {
                        ret = true;
                        break;
                    }
                }
            }
        }
        return ret;

    } catch(e) {
        console.log(e);
    }
};

